set -e
mkdir -p ~/ladyfolks-build && cd ~/ladyfolks-build
cat > ladyfolks.b64 <<'B64'

B64
base64 -d ladyfolks.b64 > ladyfolks.zip
echo "Verifying paste integrity..."
if ! unzip -t ladyfolks.zip >/dev/null 2>&1; then echo "STOP: paste incomplete. Re-copy the whole block and run again."; exit 1; fi
got=$(sha256sum ladyfolks.zip | cut -d' ' -f1)
[ "$got" = "8f239618759b068a74982fe5e2c10efacd74fc69dd202c2a15375a48fcf4759a" ] || { echo "STOP: checksum mismatch (paste truncated). Re-copy and rerun."; exit 1; }
echo "Integrity OK."
rm -rf ladyfolks && unzip -oq ladyfolks.zip && cd ladyfolks
git init -q
git config user.email "readeasy30@users.noreply.github.com"
git config user.name "Readeasy30"
git add -A
git commit -qm "ladyfolks: multi-tenant website builder"
git branch -M main
gh auth setup-git
gh repo create Readeasy30/ladyfolks --public 2>/dev/null || true
git remote add origin https://github.com/Readeasy30/ladyfolks.git 2>/dev/null || git remote set-url origin https://github.com/Readeasy30/ladyfolks.git
git push -u origin main
echo "DONE -> https://github.com/Readeasy30/ladyfolks"
